import { chromium } from 'playwright';

const browser = await chromium.launch();
const context = await browser.newContext();
const page = await context.newPage();
await page.goto('https://example.com');
await browser.close();

page.on('dialog', async dialog => {
  console.log(dialog.message());
  await dialog.accept(); // অথবা dialog.dismiss();
});
await page.click('#alertButton'); // অথবা #confirmButton, #promptButton

const productNames = await page.locator('.product-name').allTextContents();
const productPrices = await page.locator('.product-price').allTextContents();

for (let i = 0; i < productNames.length; i++) {
  console.log(`Product: ${productNames[i]}, Price: ${productPrices[i]}`);
}

const products = await page.locator('.product-item').evaluateAll(list => {
  return list.map(item => {
    return {
      name: item.querySelector('.product-name').innerText,
      price: item.querySelector('.product-price').innerText
    }
  })
});

console.log(products);

